class DeepLinkHandler extends StatefulWidget {
  @override
  _DeepLinkHandlerState createState() => _DeepLinkHandlerState();
}

class _DeepLinkHandlerState extends State<DeepLinkHandler> {
  StreamSubscription? _linkSubscription;
  String? _latestLink;
  String? _initialLink;

  @override
  void initState() {
    super.initState();
    _initDeepLinkListener();
    _handleInitialLink();
  }

  Future<void> _initDeepLinkListener() async {
    _linkSubscription = linkStream.listen((String? link) {
      if (link != null) {
        setState(() {
          _latestLink = link;
        });
        _handleDeepLink(link);
      }
    }, onError: (err) {
      setState(() {
        _latestLink = 'Error: $err';
      });
    });
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        setState(() {
          _initialLink = initialLink;
        });
        _handleDeepLink(initialLink);
      }
    } on PlatformException {
      setState(() {
        _initialLink = 'Failed to get initial link';
      });
    }
  }

  void _handleDeepLink(String link) {
    final uri = Uri.parse(link);
    
    if (uri.scheme == 'myapp') {
      final pathSegments = uri.pathSegments;
      
      if (pathSegments.isEmpty) {
        Navigator.of(context).pushReplacementNamed('/home');
        return;
      }

      final route = pathSegments[0];
      final parameters = <String, dynamic>{};
      
      if (pathSegments.length > 1) {
        for (int i = 1; i < pathSegments.length; i++) {
          parameters['param$i'] = pathSegments[i];
        }
      }
      
      uri.queryParameters.forEach((key, value) {
        parameters[key] = value;
      });

      switch (route) {
        case 'profile':
          final userId = pathSegments.length > 1 ? pathSegments[1] : null;
          Navigator.of(context).pushReplacement(
            MaterialPageRoute(
              builder: (context) => ProfileScreen(
                userId: userId,
                parameters: parameters,
              ),
            ),
          );
          break;
          
        case 'payment':
          final action = pathSegments.length > 1 ? pathSegments[1] : null;
          Navigator.of(context).pushReplacement(
            MaterialPageRoute(
              builder: (context) => PaymentScreen(
                action: action,
                parameters: parameters,
              ),
            ),
          );
          break;
          
        default:
          Navigator.of(context).pushReplacementNamed('/home');
      }
    }
  }

  @override
  void dispose() {
    _linkSubscription?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return HomeScreen(
      latestLink: _latestLink,
      initialLink: _initialLink,
    );
  }
}

